/**
 * Style Dictionary Config — Tokens Studio Source (Figma)
 *
 * Reads flattened DTCG tokens from design-tokens/tokens-figma.json
 * (generated by scripts/flatten-tokens-studio.js from Tokens Studio export)
 * and produces multi-platform outputs in build/figma/.
 *
 * Uses @tokens-studio/sd-transforms for proper handling of
 * Tokens Studio-specific features (math expressions, composite tokens).
 *
 * Run: node scripts/flatten-tokens-studio.js && npx style-dictionary build --config sd.config.tokens-studio.mjs
 */

import { register } from '@tokens-studio/sd-transforms';
import StyleDictionary from 'style-dictionary';

// Register Tokens Studio transforms (math resolution, dimension px, etc.)
register(StyleDictionary);

// ─── SwiftUI Format ─────────────────────────────────────────────
// Generates namespaced Swift enums with SwiftUI types.
// Each file is filtered to a token category, so border-radius.lg
// and border-width.lg land in separate enums — no collision.

function hexToSwiftColor(hex) {
  const h = hex.replace('#', '');
  const r = (parseInt(h.slice(0, 2), 16) / 255).toFixed(4);
  const g = (parseInt(h.slice(2, 4), 16) / 255).toFixed(4);
  const b = (parseInt(h.slice(4, 6), 16) / 255).toFixed(4);
  return `Color(red: ${r}, green: ${g}, blue: ${b})`;
}

StyleDictionary.registerFormat({
  name: 'swiftui/enum',
  format: ({ dictionary, options, file }) => {
    const { enumName = 'BDSTokens' } = options;
    const header = [
      `// ${file.destination}`,
      '// Auto-generated by Style Dictionary — do not edit',
      '',
      'import SwiftUI',
      '',
    ].join('\n');

    const lines = dictionary.allTokens.map((token) => {
      const name = token.name;
      const value = token.value ?? token.$value;
      const type = token.$type ?? token.type ?? '';
      const desc = token.$description ? ` /// ${token.$description}` : '';

      // Color → SwiftUI Color
      if (type === 'color' || (typeof value === 'string' && /^#[0-9a-f]{6,8}$/i.test(value))) {
        return `    public static let ${name} = ${hexToSwiftColor(value)}${desc}`;
      }

      // Text values (font families, easing, etc.)
      if (type === 'text' || type === 'fontFamily' || type === 'cubicBezier') {
        const escaped = String(value).replace(/"/g, '\\"');
        return `    public static let ${name} = "${escaped}"${desc}`;
      }

      // Numeric dimension → CGFloat
      const num = parseFloat(String(value));
      if (!isNaN(num)) {
        return `    public static let ${name}: CGFloat = ${num}${desc}`;
      }

      // Fallback: string
      return `    public static let ${name} = "${String(value)}"${desc}`;
    });

    return `${header}public enum ${enumName} {\n${lines.join('\n')}\n}\n`;
  },
});

// ─── SwiftUI file definitions ───────────────────────────────────
// Each category gets its own enum to avoid naming collisions.
// border-radius/lg → BDSBorderRadius.lg
// border-width/lg  → BDSBorderWidth.lg  (no collision)

const SEMANTIC_COLOR_GROUPS = ['background', 'text', 'border', 'surface', 'page'];

const swiftFiles = [
  {
    destination: 'BDSColor.swift',
    enumName: 'BDSColor',
    filter: (token) => {
      const top = token.path[0];
      // Primitive colors only — semantic colors go in BDSSemanticColor
      if (SEMANTIC_COLOR_GROUPS.includes(top)) return false;
      return ['color', 'theme'].includes(top);
    },
  },
  {
    destination: 'BDSSemanticColor.swift',
    enumName: 'BDSSemanticColor',
    filter: (token) => SEMANTIC_COLOR_GROUPS.includes(token.path[0]),
  },
  {
    destination: 'BDSFontSize.swift',
    enumName: 'BDSFontSize',
    filter: (token) => token.path[0] === 'font-size',
  },
  {
    destination: 'BDSFontWeight.swift',
    enumName: 'BDSFontWeight',
    filter: (token) => token.path[0] === 'font-weight',
  },
  {
    destination: 'BDSFontFamily.swift',
    enumName: 'BDSFontFamily',
    filter: (token) => {
      const top = token.path[0];
      if (top === 'font-family') return true;
      // icon/logo root tokens only (font-family values), not icon.tiny/xs/etc. sizes
      return ['icon', 'logo'].includes(top) && token.path.length === 1;
    },
  },
  {
    destination: 'BDSLineHeight.swift',
    enumName: 'BDSLineHeight',
    filter: (token) => token.path[0] === 'font-line-height',
  },
  {
    destination: 'BDSTypography.swift',
    enumName: 'BDSTypography',
    filter: (token) => {
      const top = token.path[0];
      return ['body', 'heading', 'display', 'label', 'subtitle'].includes(top)
        || (top === 'icon' && token.path.length > 1); // icon.tiny, icon.xs, etc.
    },
  },
  {
    destination: 'BDSSpace.swift',
    enumName: 'BDSSpace',
    filter: (token) => {
      const top = token.path[0];
      return ['space', 'gap', 'padding'].includes(top);
    },
  },
  {
    destination: 'BDSSize.swift',
    enumName: 'BDSSize',
    filter: (token) => {
      const top = token.path[0];
      return ['size', 'mobile', 'tablet', 'web'].includes(top);
    },
  },
  {
    destination: 'BDSBorderRadius.swift',
    enumName: 'BDSBorderRadius',
    filter: (token) => token.path[0] === 'border-radius',
  },
  {
    destination: 'BDSBorderWidth.swift',
    enumName: 'BDSBorderWidth',
    filter: (token) => token.path[0] === 'border-width',
  },
  {
    destination: 'BDSShadow.swift',
    enumName: 'BDSShadow',
    filter: (token) => {
      const top = token.path[0];
      return ['shadow-blur', 'shadow-offset', 'shadow-spread', 'blur-radius', 'box-shadow'].includes(top);
    },
  },
  {
    destination: 'BDSMotion.swift',
    enumName: 'BDSMotion',
    filter: (token) => {
      const top = token.path[0];
      return ['duration', 'delay', 'easing', 'iteration'].includes(top);
    },
  },
];

// ─── Config ─────────────────────────────────────────────────────

export default {
  source: ['design-tokens/tokens-figma.json'],
  preprocessors: ['tokens-studio'],
  platforms: {
    css: {
      transformGroup: 'tokens-studio',
      transforms: ['name/kebab'],
      buildPath: 'build/figma/css/',
      files: [
        {
          destination: 'variables.css',
          format: 'css/variables',
          options: {
            outputReferences: true,
            selector: ':root',
          },
        },
      ],
    },

    js: {
      transformGroup: 'tokens-studio',
      transforms: ['name/camel'],
      buildPath: 'build/figma/js/',
      files: [
        {
          destination: 'tokens.mjs',
          format: 'javascript/es6',
        },
        {
          destination: 'tokens.d.ts',
          format: 'typescript/es6-declarations',
        },
      ],
    },

    swift: {
      transformGroup: 'tokens-studio',
      transforms: ['name/camel'],
      buildPath: 'build/figma/swift/',
      files: swiftFiles.map(({ destination, enumName, filter }) => ({
        destination,
        format: 'swiftui/enum',
        filter,
        options: { enumName },
      })),
    },
  },
};
